  // =========================================================================
  // keep_properties
  // =========================================================================
  test("keep_properties") {
    assertCompresses(
      input = "a[\"foo\"] = \"bar\"",
      expected = "a[\"foo\"] = \"bar\"",
      options = AllOff.copy(
        evaluate = true,
        properties = false
      )
    )
  }

  // =========================================================================
  // dot_properties
  // =========================================================================
  test("dot_properties") {
    assertCompresses(
      input = """a["foo"] = "bar";
        a["if"] = "if";
        a["*"] = "asterisk";
        a["\u0EB3"] = "unicode";
        a[""] = "whitespace";
        a["1_1"] = "foo"""".stripMargin.trim,
      expected = """a.foo = "bar";
        a["if"] = "if";
        a["*"] = "asterisk";
        a["\u0EB3"] = "unicode";
        a[""] = "whitespace";
        a["1_1"] = "foo"""".stripMargin.trim,
      options = AllOff.copy(
        evaluate = true,
        properties = true
      )
    )
  }

