  // =========================================================================
  // first_256_unicode_chars_as_properties
  // Strings built at runtime: \u0022/\u005C in """...""" are Scala Unicode
  // escapes processed before lexing, breaking the string literal.
  // =========================================================================
  test("first_256_unicode_chars_as_properties") {
    val entries  = (0 to 255).map(i => "\"\\u%04X\":%3d".format(i, i)).mkString(",")
    val input    = "var o={" + entries + "}"
    val expected = input
    assertCompresses(input, expected, AllOff)
  }

