      input = "var Foo = { foo: function() { return Bar.bar() } }",
      expected = "var r={o:function(){return a.bar()}}",
      options = AllOff
    )
  }

  // =========================================================================
  // mangle_undeclared_properties
  // =========================================================================
  test("mangle_undeclared_properties".fail) {
    assertCompresses(
      input = "var Foo = { foo: function() { return Bar.bar() } }",
      expected = "var r={o:function(){return a.t()}}",
      options = AllOff
    )
  }

}
